-- V4: Introduce decks and seed 70 decks / 700 questions across 26 categories.
--
-- Backward compatible with V1/V2:
--   * existing categories + questions are untouched;
--   * questions.deck_id is nullable so legacy category-based rows still work;
--   * questions.title / hint / sub_topic are nullable additive columns.
--
-- Seed shape (imported from the curated 70_decks.sql + 700_questions.sql):
--   70 decks across 26 categories (interview-prep + academic disciplines)
--   700 questions (10 per deck), IDs q-0001..q-0700
--   Difficulty mix: 210 EASY / 350 MEDIUM / 140 HARD (3/5/2 per deck)
--   Each question has a short title, full prompt, hint, and sub-topic.
--
-- Deck + question UUIDs are deterministic (uuid5) so the migration is
-- re-runnable with ON CONFLICT (id) DO NOTHING.

-- 1. decks table ---------------------------------------------------------
CREATE TABLE IF NOT EXISTS decks (
    id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    title         VARCHAR(140) NOT NULL,
    category      VARCHAR(80)  NOT NULL,
    color_hex     VARCHAR(9)   NOT NULL DEFAULT '#2e8bee',
    description   TEXT,
    question_count INT NOT NULL DEFAULT 0,
    created_at    TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at    TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_decks_title UNIQUE (title)
);
CREATE INDEX IF NOT EXISTS idx_decks_category ON decks(category);

-- 2. link questions to decks + add title/hint/sub_topic (additive) --------
ALTER TABLE questions ADD COLUMN IF NOT EXISTS deck_id UUID REFERENCES decks(id) ON DELETE SET NULL;
ALTER TABLE questions ADD COLUMN IF NOT EXISTS title VARCHAR(200);
ALTER TABLE questions ADD COLUMN IF NOT EXISTS hint TEXT;
ALTER TABLE questions ADD COLUMN IF NOT EXISTS sub_topic VARCHAR(120);
CREATE INDEX IF NOT EXISTS idx_questions_deck ON questions(deck_id) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_questions_sub_topic ON questions(sub_topic) WHERE deleted_at IS NULL;

