-- 4. seed 70 decks -------------------------------------------------------
ON CONFLICT (id) DO NOTHING;

-- 5. seed 700 questions (10 per deck) ------------------------------------
-- Maps the curated q-0001..q-0700 to UUIDs and links each to its deck.
-- title/hint/sub_topic are populated from the curated content.
ON CONFLICT (id) DO NOTHING;

